func lookupGeneratedProducerGroup(kind ProducerKind, key ProducerKey) (generatedProducerGroup, bool) {
	index, ok := generatedProducerGroupIndex[generatedProducerLookupKey{Kind: kind, Key: key}]
	if !ok {
		return generatedProducerGroup{}, false
	}
	return generatedProducerGroups[index], true
}

func resolveGeneratedProducerIdentity(kind ProducerKind, key ProducerKey, context ClassificationContext) (generatedProducerIdentity, error) {
	group, ok := lookupGeneratedProducerGroup(kind, key)
	if !ok {
		return generatedProducerIdentity{}, fmt.Errorf("unknown generated producer classification %s/%s", kind, key)
	}
	hasBucket := context.Bucket != ""
	hasEventName := context.EventName != ""
	if hasBucket != hasEventName {
		return generatedProducerIdentity{}, fmt.Errorf("generated producer context identity requires bucket and event name together")
	}
	selectIdentity := func(identityKey generatedProducerIdentityKey) (generatedProducerIdentity, bool) {
		identity, found := generatedProducerIdentities[identityKey]
		if !found {
			return generatedProducerIdentity{}, false
		}
		identity.LegacyMandatoryRules = append([]MandatoryRule(nil), group.LegacyMandatoryRules...)
		identity.CompanionRules = append([]CompanionRule(nil), group.CompanionRules...)
		return identity, true
	}
	selectContext := func() (generatedProducerIdentity, bool) {
		set, found := generatedProducerContextIdentitySets[group.ContextIdentitySetID]
		if !found {
			return generatedProducerIdentity{}, false
		}
		for _, identityKey := range set.IdentityKeys {
			if identityKey.Bucket == context.Bucket && identityKey.EventName == context.EventName {
				return selectIdentity(identityKey)
			}
		}
		return generatedProducerIdentity{}, false
	}
	switch group.EventNamePolicy {
	case EventNameFixed:
		identity, found := selectIdentity(group.DefaultIdentityKey)
		if !group.HasDefaultIdentity || !found {
			return generatedProducerIdentity{}, fmt.Errorf("generated producer fixed identity is unavailable")
		}
		if hasBucket && (identity.Bucket != context.Bucket || identity.EventName != context.EventName) {
			return generatedProducerIdentity{}, fmt.Errorf("generated producer fixed identity disagrees with supplied context")
		}
		return identity, nil
	case EventNameContextOptional:
		if !hasBucket {
			identity, found := selectIdentity(group.DefaultIdentityKey)
			if !group.HasDefaultIdentity || !found {
				return generatedProducerIdentity{}, fmt.Errorf("generated producer default identity is unavailable")
			}
			return identity, nil
		}
		if identity, found := selectContext(); found {
			return identity, nil
		}
	case EventNameContextRequired:
		if !hasBucket {
			return generatedProducerIdentity{}, fmt.Errorf("generated producer classification requires a context identity")
		}
		if identity, found := selectContext(); found {
			return identity, nil
		}
	}
	return generatedProducerIdentity{}, fmt.Errorf("generated producer context identity is not registered for %s/%s", kind, key)
}

func generatedProducerGroupIdentities(group generatedProducerGroup) []generatedProducerIdentity {
	result := make([]generatedProducerIdentity, 0)
	appendIdentity := func(identityKey generatedProducerIdentityKey) {
		identity, found := generatedProducerIdentities[identityKey]
		if !found {
			panic("generated producer identity key is unavailable")
		}
		identity.LegacyMandatoryRules = append([]MandatoryRule(nil), group.LegacyMandatoryRules...)
		identity.CompanionRules = append([]CompanionRule(nil), group.CompanionRules...)
		result = append(result, identity)
	}
	if group.HasDefaultIdentity {
		appendIdentity(group.DefaultIdentityKey)
	}
	if group.ContextIdentitySetID != "" {
		set, found := generatedProducerContextIdentitySets[group.ContextIdentitySetID]
		if !found {
			panic("generated producer context identity set is unavailable")
		}
		for _, identityKey := range set.IdentityKeys {
			appendIdentity(identityKey)
		}
	}
	return result
}

